159	
160	    -- *************************************************************************
161	    -- Helpers
162	    -- *************************************************************************
163	    -- Coun the number of elements in a array string (separated by ",")
164	    function countCommaSepElems (input : string) return natural is
165	        variable Count_v : natural := 1;
166	        variable Idx_v   : integer := input'low;
167	    begin
168	
169	        -- loop through all characters
170	        while Idx_v <= input'high loop
171	            if input(Idx_v) = ',' then
172	                Count_v := Count_v + 1;
173	            end if;
174	            Idx_v := Idx_v + 1;
175	        end loop;
176	
177	        return Count_v;
178	    end function;
179	
180	    -- *************************************************************************
181	    -- Public Functions
182	    -- *************************************************************************
183	
184	    -- *** Log2 integer ***
185	    function log2 (arg : in natural) return natural is
186	        variable ArgShift_v : natural := arg;
187	        variable Log2_v     : natural := 0;
188	    begin
189	
190	        -- Calculate log2
191	        while ArgShift_v > 1 loop
192	            ArgShift_v := ArgShift_v / 2;
193	            Log2_v     := Log2_v + 1;
194	        end loop;
195	
196	        return Log2_v;
197	    end function;
198	
199	    -- *** Log2Ceil integer ***
200	    function log2ceil (arg : in natural) return natural is
201	    begin
202	        if arg = 0 then
203	            return 0;
204	        end if;
205	        return log2(arg * 2 - 1);
206	    end function;
207	
208	    -- *** Log2Ceil real ***
209	    function log2ceil (arg : in real) return natural is
210	        variable v        : real    := arg;
211	        variable Result_v : natural := 0;
212	    begin
213	
214	        -- Calculat elog2
215	        while v > 1.0 loop
216	            v        := v / 2.0;
217	            Result_v := Result_v + 1;
218	        end loop;
219	
220	        return Result_v;
221	    end function;
222	
223	    -- *** isPower2 ***
224	    function isPower2 (arg : in natural) return boolean is
225	    begin
226	        if log2(arg) = log2ceil(arg) then
227	            return true;
228	        else
229	            return false;
230	        end if;
231	    end function;
232	
233	    -- *** GreatestCommonFactor ***
234	    function greatestCommonFactor (
235	        a : in positive;
236	        b : in positive) return positive is
237	        variable Gcd_v : positive := min(a, b);
238	    begin
239	
240	        while Gcd_v > 1 loop
241	            if a mod Gcd_v = 0 and b mod Gcd_v = 0 then
242	                return Gcd_v;
243	            end if;
244	            Gcd_v := Gcd_v - 1;
245	        end loop;
246	
247	        return Gcd_v;
248	    end function;
249	
250	    -- *** leastCommonMultiple ***
251	    function leastCommonMultiple (
252	        a : in positive;
253	        b : in positive) return positive is
254	    begin
255	        return a * b / greatestCommonFactor(a, b);
256	    end function;
