408	    -- *** count (integer) ***
409	    function count (
410	        a : in IntegerArray_t;
411	        v : in integer) return integer is
412	        variable Cnt_v : integer := 0;
413	    begin
414	
415	        -- Count number of ocurrences
416	        for idx in a'low to a'high loop
417	            if a(idx) = v then
418	                Cnt_v := Cnt_v + 1;
419	            end if;
420	        end loop;
