497	    -- *** integer from stdl ***
498	    function fromStdl (input : std_logic) return integer is
499	    begin
500	        -- synthesis translate_off
501	        assert input = '0' or input = '1'
502	            -- errorMessage() cannot be used to avoid cyclic dependency between olo_base_pkg_math and olo_base_pkg_string
503	            report "olo_base_pkg_math.fromStdl(): Illegal argument"
504	            severity error;
505	        -- synthesis translate_on
506	        if input = '0' then
507	            return 0;
508	        else
509	            return 1;
510	        end if;
511	    end function;
512	
513	    -- convert string to real
514	    function fromString (input : string) return real is
515	        constant Nbsp_c       : character := character'val(160);
516	        variable Idx_v        : integer   := input'low;
517	        variable IsNeg_v      : boolean   := false;
518	        variable ValInt_v     : integer   := 0;
519	        variable ValFrac_v    : real      := 0.0;
520	        variable FracDigits_v : integer   := 0;
521	        variable Exp_v        : integer   := 0;
522	        variable ExpNeg_v     : boolean   := false;
523	        variable ValAbs_v     : real      := 0.0;
524	    begin
525	
526	        -- skip leading white-spaces (space, non-breaking space or horizontal tab)
527	        while (Idx_v <= input'high) and (input(Idx_v) = ' ' or input(Idx_v) = Nbsp_c or input(Idx_v) = HT) loop
528	            Idx_v := Idx_v + 1;
529	        end loop;
530	
531	        -- Check sign
532	        if (Idx_v <= input'high) and ((input(Idx_v) = '-') or (input(Idx_v) = '+')) then
533	            IsNeg_v := (input(Idx_v) = '-');
534	            Idx_v   := Idx_v + 1;
535	        end if;
536	
537	        -- Parse Integer
538	        while (Idx_v <= input'high) and (input(Idx_v) <= '9') and (input(Idx_v) >= '0') loop
539	            ValInt_v := ValInt_v * 10 + (character'pos(input(Idx_v)) - character'pos('0'));
540	            Idx_v    := Idx_v + 1;
541	        end loop;
542	
543	        -- Check decimal point
544	        if (Idx_v <= input'high) then
545	            if input(Idx_v) = '.' then
546	                Idx_v := Idx_v + 1;
547	
548	                -- Parse Fractional
549	                while (Idx_v <= input'high) and (input(Idx_v) <= '9') and (input(Idx_v) >= '0') loop
550	                    ValFrac_v    := ValFrac_v * 10.0 + real((character'pos(input(Idx_v)) - character'pos('0')));
551	                    FracDigits_v := FracDigits_v + 1;
552	                    Idx_v        := Idx_v + 1;
553	                end loop;
554	
555	            end if;
556	        end if;
557	
558	        -- Check exponent
559	        if (Idx_v <= input'high) then
560	            if (input(Idx_v) = 'E') or (input(Idx_v) = 'e') then
561	                Idx_v := Idx_v + 1;
562	                -- Check sign
563	                if (Idx_v <= input'high) and ((input(Idx_v) = '-') or (input(Idx_v) = '+')) then
564	                    ExpNeg_v := (input(Idx_v) = '-');
565	                    Idx_v    := Idx_v + 1;
566	                end if;
567	
568	                -- Parse Integer
569	                while (Idx_v <= input'high) and (input(Idx_v) <= '9') and (input(Idx_v) >= '0') loop
570	                    Exp_v := Exp_v * 10 + (character'pos(input(Idx_v)) - character'pos('0'));
571	                    Idx_v := Idx_v + 1;
572	                end loop;
573	
574	                -- Handle negative exponent
575	                if ExpNeg_v then
576	                    Exp_v := -Exp_v;
577	                end if;
578	            end if;
579	        end if;
580	
581	        -- Return
582	        ValAbs_v := (real(ValInt_v) + ValFrac_v / 10.0**real(FracDigits_v)) * 10.0**real(Exp_v);
583	        if IsNeg_v then
584	            return -ValAbs_v;
585	        else
586	            return ValAbs_v;
587	        end if;
588	    end function;
589	
590	    -- convert string to real array
591	    function fromString (input : string) return RealArray_t is
592	        variable Array_v    : RealArray_t(0 to countCommaSepElems(input) - 1) := (others => 0.0);
593	        variable ArrayIdx_v : natural                                         := 0;
594	        variable StartIdx_v : natural                                         := 1;
595	        variable EndIdx_v   : natural                                         := 1;
596	        variable CharIdx_v  : natural                                         := input'low;
597	    begin
598	
599	        -- loop through all characters
600	        while CharIdx_v <= input'high loop
601	            if input(CharIdx_v) = ',' then
602	                EndIdx_v            := CharIdx_v - 1;
603	                Array_v(ArrayIdx_v) := fromString(input(StartIdx_v to EndIdx_v));
604	                ArrayIdx_v          := ArrayIdx_v + 1;
605	                StartIdx_v          := CharIdx_v + 1;
606	            end if;
607	            CharIdx_v := CharIdx_v + 1;
608	        end loop;
609	
610	        -- handle last element
611	        if StartIdx_v <= input'high then
612	            Array_v(ArrayIdx_v) := fromString(input(StartIdx_v to input'high));
613	        end if;
614	
615	        return Array_v;
616	    end function;
617	
618	    -- *** get the maximum out of an array of integer ***
619	    function maxArray (a : in IntegerArray_t) return integer is
620	        variable Max_v : integer := 0;
621	    begin
622	
623	        -- Loop through all elements
624	        for idx in a'low to a'high loop
625	            if max(Max_v, a(idx)) > Max_v then
626	                Max_v := a(idx);
627	            end if;
628	        end loop;
629	
630	        return Max_v;
631	    end function;
632	
633	    -- *** get the maximum out of an array of real ***
634	    function maxArray (a : in RealArray_t) return real is
635	        variable Max_v : real := 0.0;
636	    begin
637	
638	        -- Loop through all elements
639	        for idx in a'low to a'high loop
640	            if max(Max_v, a(idx)) > Max_v then
641	                Max_v := a(idx);
642	            end if;
643	        end loop;
644	
645	        return Max_v;
646	    end function;
647	
648	    -- *** get the minimum out of an array of integer ***
649	    function minArray (a : in IntegerArray_t) return integer is
650	        variable Min_v : integer := 0;
651	    begin
652	
653	        -- Loop through all elements
654	        for idx in a'low to a'high loop
655	            if min(Min_v, a(idx)) < Min_v then
656	                Min_v := a(idx);
657	            end if;
658	        end loop;
659	
660	        return Min_v;
661	    end function;
662	
663	    -- *** get the minimum out of an array of real ***
664	    function minArray (a : in RealArray_t) return real is
665	        variable Min_v : real := 0.0;
666	    begin
667	
668	        -- Loop through all elements
669	        for idx in a'low to a'high loop
670	            if min(Min_v, a(idx)) < Min_v then
671	                Min_v := a(idx);
672	            end if;
673	        end loop;
674	
675	        return Min_v;
676	    end function;
677	
678	end package body;
