116	package body olo_base_pkg_logic is
117	
118	    -- *** ZerosVector ***
119	    function zerosVector (size : in natural) return std_logic_vector is
120	        constant Vector_c : std_logic_vector(size - 1 downto 0) := (others => '0');
121	    begin
122	        return Vector_c;
123	    end function;
124	
125	    -- *** OnesVector ***
126	    function onesVector (size : in natural) return std_logic_vector is
127	        constant Vector_c : std_logic_vector(size - 1 downto 0) := (others => '1');
128	    begin
129	        return Vector_c;
130	    end function;
131	
132	    -- *** ShiftLeft ***
133	    function shiftLeft (
134	        arg  : in std_logic_vector;
135	        bits : in integer;
136	        fill : in std_logic := '0') return std_logic_vector is
137	        constant ArgDownto_c : std_logic_vector(arg'high downto arg'low) := arg;
138	        variable Vector_v    : std_logic_vector(ArgDownto_c'range);
139	    begin
140	        if bits < 0 then
141	            return shiftRight(ArgDownto_c, -bits, fill);
142	        else
143	            Vector_v(Vector_v'left downto bits)      := ArgDownto_c(ArgDownto_c'left - bits downto ArgDownto_c'right);
144	            Vector_v(bits - 1 downto Vector_v'right) := (others => fill);
145	            return Vector_v;
146	        end if;
147	    end function;
148	
149	    -- *** ShiftRight ***
150	    function shiftRight (
151	        arg  : in std_logic_vector;
152	        bits : in integer;
153	        fill : in std_logic := '0') return std_logic_vector is
154	        constant ArgDownto_c : std_logic_vector(arg'high downto arg'low) := arg;
155	        variable Vector_v    : std_logic_vector(ArgDownto_c'range);
156	    begin
157	        if bits < 0 then
158	            return shiftLeft(ArgDownto_c, -bits, fill);
159	        else
160	            Vector_v(Vector_v'left - bits downto Vector_v'right)    := ArgDownto_c(ArgDownto_c'left downto bits);
161	            Vector_v(Vector_v'left downto Vector_v'left - bits + 1) := (others => fill);
162	            return Vector_v;
163	        end if;
164	    end function;
165	
166	    -- *** BinaryToGray ***
167	    function binaryToGray (binary : in std_logic_vector) return std_logic_vector is
168	        variable Gray_v : std_logic_vector(binary'range);
169	    begin
170	        Gray_v := binary xor ('0' & binary(binary'high downto binary'low + 1));
171	        return Gray_v;
172	    end function;
