174	    -- *** GrayToBinary ***
175	    function grayToBinary (gray : in std_logic_vector) return std_logic_vector is
176	        variable Binary_v : std_logic_vector(gray'range);
177	    begin
178	        Binary_v(Binary_v'high) := gray(gray'high);
179	
180	        -- Loop through all bits
181	        for b in gray'high - 1 downto gray'low loop
182	            Binary_v(b) := gray(b) xor Binary_v(b + 1);
183	        end loop;
184	
185	        return Binary_v;
186	    end function;
187	
188	    -- *** PpcOr ***
189	    function ppcOr (inp : in std_logic_vector) return std_logic_vector is
190	        -- Constants
191	        constant Stages_c    : integer := log2ceil(inp'length);
192	        constant Pwr2Width_c : integer := 2**Stages_c;
193	
194	        -- Types
195	        type StageOut_t is array (natural range <>) of std_logic_vector(Pwr2Width_c downto 0);
196	
197	        -- Variables
198	        variable StageOut_v : StageOut_t(0 to Stages_c) := (others => (others => '0'));
199	        variable BinCnt_v   : unsigned(Pwr2Width_c - 1 downto 0);
200	    begin
201	        StageOut_v(0)                          := (others => '0');
202	        StageOut_v(0)(inp'length - 1 downto 0) := inp;
203	
204	        -- Loop through all stages
205	        for stage in 0 to Stages_c - 1 loop
