64	
65	    -- *** toUpper() ***
66	    function toUpper (a : in string) return string is
67	        variable Res_v        : string(a'range);
68	        variable CharIdx_v    : natural;
69	        constant LowerUpper_c : natural := character'pos('a') - character'pos('A');
70	    begin
71	
72	        -- Loop over characters
73	        for i in a'range loop
74	            CharIdx_v := character'pos(a(i));
75	            if CharIdx_v >= character'pos('a') and CharIdx_v <= character'pos('z') then
76	                CharIdx_v := CharIdx_v - LowerUpper_c;
