86	        variable Res_v        : string(a'range);
87	        variable CharIdx_v    : natural;
88	        constant LowerUpper_c : natural := character'pos('a') - character'pos('A');
89	    begin
90	
91	        -- Loop over characters
92	        for i in a'range loop
93	            CharIdx_v := character'pos(a(i));
94	            if CharIdx_v >= character'pos('A') and CharIdx_v <= character'pos('Z') then
95	                CharIdx_v := CharIdx_v + LowerUpper_c;
96	            end if;
97	            Res_v(i) := character'val(CharIdx_v);
98	        end loop;
99	
100	        return Res_v;
101	    end function;
102	
103	    -- *** compareNoCase() ***
104	    function compareNoCase (
105	        a : in string;
106	        b : in string) return boolean is
107	    begin
108	        return toUpper(trim(a)) = toUpper(trim(b));
109	    end function;
