111	    -- *** trim() ***
112	    function trim (a : in string) return string is
113	        variable StartIdx_v : natural := a'left;
114	        variable EndIdx_v   : natural := a'right;
115	    begin
116	
117	        -- Find first non-whitespace character
118	        while StartIdx_v < a'right and a(StartIdx_v) = ' ' loop
119	            StartIdx_v := StartIdx_v + 1;
120	        end loop;
121	
122	        -- Find last non-whitespace character
123	        while EndIdx_v > a'left and a(EndIdx_v) = ' ' loop
124	            EndIdx_v := EndIdx_v - 1;
125	        end loop;
126	
127	        -- Return trimmed string
128	        return a(StartIdx_v to EndIdx_v);
129	    end function;
