131	    -- *** hex2StdLogicVector() ***
132	    function hex2StdLogicVector (
133	        a         : in string;
134	        bits      : in natural;
135	        hasPrefix : in boolean := false) return std_logic_vector is
136	        -- Declarations
137	        constant Trimmed_c   : string                                   := trim(toLower(a));
138	        constant MaxBits_c   : natural                                  := max(choose(hasPrefix, (Trimmed_c'length-2) * 4, Trimmed_c'length * 4), 0);
139	        variable StdlvFull_v : std_logic_vector(MaxBits_c - 1 downto 0) := (others => '0');
140	        variable Result_v    : std_logic_vector(bits - 1 downto 0)      := (others => '0');
141	        variable LowIdx_v    : natural                                  := 0;
142	        variable Nibble_v    : std_logic_vector(3 downto 0);
143	    begin
144	        -- For empty string return zero
145	        if Trimmed_c'length = 0 then
146	            return Result_v;
147	        end if;
148	
149	        -- Check prefix
150	        if hasPrefix then
151	            -- synthesis translate_off
152	            assert Trimmed_c(Trimmed_c'left to Trimmed_c'left+1) = "0x"
153	                report errorMessage("olo_base_pkg_string.hex2StdLogicVector()", "Invalid prefix - expected prefix is 0x - string: " & a)
154	                severity error;
155	            -- synthesis translate_on
156	            -- coverage
157	            LowIdx_v := LowIdx_v + 2;
158	        end if;
159	
160	        -- Convert
161	        for i in Trimmed_c'left+LowIdx_v to Trimmed_c'right loop
162	
163	            -- Convert Nibble
164	            case Trimmed_c(i) is
165	                when '0' => Nibble_v := x"0";
166	                when '1' => Nibble_v := x"1";
167	                when '2' => Nibble_v := x"2";
168	                when '3' => Nibble_v := x"3";
169	                when '4' => Nibble_v := x"4";
170	                when '5' => Nibble_v := x"5";
171	                when '6' => Nibble_v := x"6";
172	                when '7' => Nibble_v := x"7";
173	                when '8' => Nibble_v := x"8";
174	                when '9' => Nibble_v := x"9";
175	                when 'a' => Nibble_v := x"A";
176	                when 'b' => Nibble_v := x"B";
177	                when 'c' => Nibble_v := x"C";
178	                when 'd' => Nibble_v := x"D";
179	                when 'e' => Nibble_v := x"E";
180	                when 'f' => Nibble_v := x"F";
181	                -- coverage off
182	                when others =>
183	                    report errorMessage("olo_base_pkg_string.hex2StdLogicVector()", "Invalid character - only 0-9, a-f, A-F are allowed - string: " & a)
184	                        severity error;
185	                    return Result_v;
186	                -- coverage on
187	            end case;
188	
189	            -- Add nibble to result
190	            StdlvFull_v := StdlvFull_v(StdlvFull_v'left - 4 downto 0) & Nibble_v;
191	        end loop;
192	
193	        -- Convert size
194	        if bits > MaxBits_c then
195	            Result_v(MaxBits_c - 1 downto 0) := StdlvFull_v;
196	        else
